class Solution {
    private static final int MOD = (int) 1e9 + 7;
    public int countKReducibleNumbers(String s, int k) {
        int n = Integer.parseInt(s, 2);
        Boolean[][] dp = new Boolean[n + 1][k + 1];
        return count(n, k, dp);
    }

    private int count(int x, int k, Boolean[][] dp) {
        if (x == 1) return 1;
        if (k == 0) return 0;
        if (dp[x][k] != null) return dp[x][k];

        int setBits = Integer.bitCount(x);
        int res = count(setBits, k - 1, dp);
        for (int i = 1; i < x; i++) {
            if (Integer.bitCount(i) == setBits) {
                res = (res + count(i, k, dp)) % MOD;
            }
        }
        dp[x][k] = res;
        return res;
    }
}
